import React, { useState, useEffect } from "react";
import { loadStripe } from "@stripe/stripe-js";
import {Elements,CardElement,useStripe,useElements,} from "@stripe/react-stripe-js";
import axios from "axios";
import "./Payment.css";

const stripePromise = loadStripe(pk_test_51S78rcGhDM9r9QA0u5PrWubriEWhIzAhotuJYz2SiS2zo77rsjKQLbSslq2FQqvuuJvJ2ykIYKeSIbI3IRNunVOc00AnNwFcxz);

const CheckoutForm = ({ amount }) => {
  const stripe = useStripe();
  const elements = useElements();
  const [clientSecret, setClientSecret] = useState("");
  const [success, setSuccess] = useState(false);
  const [error, setError] = useState("");
  const [loading, setLoading] = useState(false);

  useEffect(() => {
    // create PaymentIntent
    axios
      .post("http://localhost:5000/create-payment-intent", { amount })
      .then((res) => setClientSecret(res.data.clientSecret))
      .catch((err) => console.log(err));
  }, [amount]);

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (!stripe || !elements || !clientSecret) return;
    setLoading(true);

    const card = elements.getElement(CardElement);

    const { paymentIntent, error } = await stripe.confirmCardPayment(clientSecret, {
      payment_method: { card },
    });

    if (error) {
      setError(error.message);
      setLoading(false);
    } else if (paymentIntent.status === "succeeded") {
      setSuccess(true);
      setLoading(false);
    }
  };

  return (
    <div className="payment-card">
      <h2>Payment Information</h2>
      {success ? (
        <div className="payment-success">
          <h3>Payment Successful!</h3>
        </div>
      ) : (
        <form onSubmit={handleSubmit}>
          <CardElement options={{ hidePostalCode: true }} />
          {error && <p className="error-msg">{error}</p>}
          <button type="submit" className="payment-btn" disabled={loading}>
            {loading ? "Processing..." : `Pay RM ${amount / 100}`}
          </button>
        </form>
      )}
    </div>
  );
};

const Payment = ({ totalAmount }) => {
  return (
    <div className="payment-page">
      <Elements stripe={stripePromise}>
        <CheckoutForm amount={totalAmount * 100} /> {/* convert to cents */}
      </Elements>
    </div>
  );
};

export default Payment;
